effect.shader:
void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*color.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-color.rgb)),1.0) * texColor.a;
    } else {
        result = vec4(color.rgb,1.0)*texColor.a;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
